mapper.select:
SELECT /* OrgMgmtMapper.listOrgMgmt */ OIM.ORGN_ID /* 조직 ID */ , OIM.ORGN_NM /* 조직명 */ , OIM.TYPE_CD /* 유형코드 */ ,(SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0003' AND CD_VAL = OIM.TYPE_CD) as TYPE_NM , OIM.ORGN_LVL_CD /* 조직레벨코드 */ ,(SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0006' AND CD_VAL = OIM.ORGN_LVL_CD) as ORGN_LVL_NM , OIM.APPL_STRT_DT /* 적용시작일자 */ , OIM.APPL_CMPLT_DT /* 적용종료일자 */ , OIM.OPEN_CRDT_LOAN_YN /* 개통여신여부 */ ,(SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'ORG0012' AND CD_VAL = OIM.OPEN_CRDT_LOAN_YN) as OPEN_CRDT_LOAN_NM , OIM.OPEN_CRDT_LOAN_STRT_DT /* 개통여신시작일자 */ , DECODE(OIM.TAXBILL_YN, 'Y','Y','N') AS TAXBILL_YN /* 세금계산서발행여부 */ , DECODE(OIM.CMSN_PRVD_YN, 'Y','Y','N') AS CMSN_PRVD_YN /* 수수료지급여부 */ , DECODE(OIM.HNDST_INVTR_YN, 'Y','Y','N') AS HNDST_INVTR_YN /* 단말재고여부 */ , OIM.BIZ_TYPE_CD /* 사업자구분 */ ,(SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0007' AND CD_VAL = OIM.BIZ_TYPE_CD) as BIZ_TYPE_NM , OIM.BIZ_REG_NUM /* 사업자등록번호 */ , OIM.CORP_REG_NUM /* 법인등록번호 */ , OIM.BIZ_CAT /* 업종 */ , OIM.BIZ_CON /* 업태 */ , OIM.RPRSEN_NM /* 대표자명 */ , OIM.RPRSEN_RRNUM /* 대표자주민번호 */ , OIM.TELNUM /* 전화번호 */ , OIM.FAX /* 팩스번호 */ , OIM.EMAIL /* 이메일 */ , OIM.ZIPCD /* 우편번호 */ , OIM.ADDR1 /* 주소1 */ , OIM.ADDR2 /* 주소2 */ , OIM.RESPN_PRSN_ID /* 담당자ID */ ,(SELECT USR_NM FROM CMN_USR_MST WHERE USR_ID = OIM.RESPN_PRSN_ID) as RESPN_PRSN_NM ,(SELECT TEL_NUM FROM CMN_USR_MST WHERE USR_ID = OIM.RESPN_PRSN_ID) as RESPN_PRSN_NUM ,(SELECT MBLPHN_NUM FROM CMN_USR_MST WHERE USR_ID = OIM.RESPN_PRSN_ID) as RESPN_PRSN_MBLPHN ,(SELECT EMAIL FROM CMN_USR_MST WHERE USR_ID = OIM.RESPN_PRSN_ID) as RESPN_PRSN_EMAIL , OIM.HNDST_ORD_YN /* 단말주문여부 */ , OIM.ORGN_STAT_CD /* 조직상태코드 */ ,(SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0005' AND CD_VAL = OIM.ORGN_STAT_CD) as ORGN_STAT_NM , OIM.TMNT_DT /* 해지일자 */ , OIM.TYPE_DTL_CD /* 유형상세코드 */ ,(SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0004' AND CD_VAL = OIM.TYPE_DTL_CD) as TYPE_DTL_NM , OIM.HGHR_ORGN_CD /* 상위조직코드 */ ,(SELECT ORGN_NM FROM ORG_ORGN_INFO_MST WHERE ORGN_ID = OIM.HGHR_ORGN_CD) as HGHR_ORGN_NM /* 상위조직코드명 */ , OIM.ORGN_GRD /* 조직등급 */ , OIM.CLOSE_YN /* 정리점여부 */ , OIM.LOGIS_CNTER_YN /* 물류센터여부 */ , OIM.REG_ID /* 등록자ID */ , TO_CHAR(OIM.REG_DTTM, 'YYYYMMDD') AS REG_DTTM /*등록일시 */ , OIM.KT_ORG_ID /* KT조직ID */ , OIM.TYPE_DTL_CD1 /* 유형상세코드1 */ , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE CD_VAL = OIM.TYPE_DTL_CD1 AND USG_YN = 'Y') as TYPE_DTL_CD_NM1 , OIM.TYPE_DTL_CD2 /* 유형상세코드2 */ , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE CD_VAL = OIM.TYPE_DTL_CD2 AND USG_YN = 'Y' AND ETC1 IS NOT NULL) as TYPE_DTL_CD_NM2 , OIM.TYPE_DTL_CD3 /* 유형상세코드3 */ , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE CD_VAL = OIM.TYPE_DTL_CD3 AND USG_YN = 'Y' AND ETC1 IS NOT NULL) as TYPE_DTL_CD_NM3 FROM ORG_ORGN_INFO_MST OIM WHERE OIM.TYPE_DTL_CD = 'Y' AND OIM.TYPE_CD != '30'
AND OIM.ORGN_ID LIKE UPPER('%'||#{orgnId}||'%')
AND OIM.ORGN_NM LIKE '%'||#{orgnNm}||'%'
AND OIM.TYPE_CD = #{typeCd}
AND OIM.TYPE_CD = '20'
AND OIM.ORGN_LVL_CD = #{orgnLvlCd}
AND OIM.ORGN_LVL_CD = '10'
AND OIM.ORGN_STAT_CD = #{orgnStatCd}
START WITH ORGN_ID = CASE WHEN EXISTS (SELECT ORGN_ID FROM ORG_ORGN_INFO_MST WHERE LOGIS_CNTER_YN = 'Y' and ORGN_ID = #{sessionUserOrgnId}) THEN '1' ELSE #{sessionUserOrgnId} END CONNECT BY PRIOR ORGN_ID = HGHR_ORGN_CD
UNION ALL
SELECT * FROM ( SELECT OIM.ORGN_ID /* 조직 ID */ , OIM.ORGN_NM /* 조직명 */ , OIM.TYPE_CD /* 유형코드 */ ,(SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0003' AND CD_VAL = OIM.TYPE_CD) as TYPE_NM , OIM.ORGN_LVL_CD /* 조직레벨코드 */ ,(SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0006' AND CD_VAL = OIM.ORGN_LVL_CD) as ORGN_LVL_NM , OIM.APPL_STRT_DT /* 적용시작일자 */ , OIM.APPL_CMPLT_DT /* 적용종료일자 */ , OIM.OPEN_CRDT_LOAN_YN /* 개통여신여부 */ ,(SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'ORG0012' AND CD_VAL = OIM.OPEN_CRDT_LOAN_YN) as OPEN_CRDT_LOAN_NM , OIM.OPEN_CRDT_LOAN_STRT_DT /* 개통여신시작일자 */ , DECODE(OIM.TAXBILL_YN, 'Y','Y','N') AS TAXBILL_YN /* 세금계산서발행여부 */ , DECODE(OIM.CMSN_PRVD_YN, 'Y','Y','N') AS CMSN_PRVD_YN /* 수수료지급여부 */ , DECODE(OIM.HNDST_INVTR_YN, 'Y','Y','N') AS HNDST_INVTR_YN /* 단말재고여부 */ , OIM.BIZ_TYPE_CD /* 사업자구분 */ ,(SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0007' AND CD_VAL = OIM.BIZ_TYPE_CD) as BIZ_TYPE_NM , OIM.BIZ_REG_NUM /* 사업자등록번호 */ , OIM.CORP_REG_NUM /* 법인등록번호 */ , OIM.BIZ_CAT /* 업종 */ , OIM.BIZ_CON /* 업태 */ , OIM.RPRSEN_NM /* 대표자명 */ , OIM.RPRSEN_RRNUM /* 대표자주민번호 */ , OIM.TELNUM /* 전화번호 */ , OIM.FAX /* 팩스번호 */ , OIM.EMAIL /* 이메일 */ , OIM.ZIPCD /* 우편번호 */ , OIM.ADDR1 /* 주소1 */ , OIM.ADDR2 /* 주소2 */ , OIM.RESPN_PRSN_ID /* 담당자ID */ ,(SELECT USR_NM FROM CMN_USR_MST WHERE USR_ID = OIM.RESPN_PRSN_ID) as RESPN_PRSN_NM ,(SELECT TEL_NUM FROM CMN_USR_MST WHERE USR_ID = OIM.RESPN_PRSN_ID) as RESPN_PRSN_NUM ,(SELECT MBLPHN_NUM FROM CMN_USR_MST WHERE USR_ID = OIM.RESPN_PRSN_ID) as RESPN_PRSN_MBLPHN ,(SELECT EMAIL FROM CMN_USR_MST WHERE USR_ID = OIM.RESPN_PRSN_ID) as RESPN_PRSN_EMAIL , OIM.HNDST_ORD_YN /* 단말주문여부 */ , OIM.ORGN_STAT_CD /* 조직상태코드 */ ,(SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0005' AND CD_VAL = OIM.ORGN_STAT_CD) as ORGN_STAT_NM , OIM.TMNT_DT /* 해지일자 */ , OIM.TYPE_DTL_CD /* 유형상세코드 */ ,(SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0004' AND CD_VAL = OIM.TYPE_DTL_CD) as TYPE_DTL_NM , OIM.HGHR_ORGN_CD /* 상위조직코드 */ ,(SELECT ORGN_NM FROM ORG_ORGN_INFO_MST WHERE ORGN_ID = OIM.HGHR_ORGN_CD) as HGHR_ORGN_NM /* 상위조직코드명 */ , OIM.ORGN_GRD /* 조직등급 */ , OIM.CLOSE_YN /* 정리점여부 */ , OIM.LOGIS_CNTER_YN /* 물류센터여부 */ , OIM.REG_ID /* 등록자ID */ , TO_CHAR(OIM.REG_DTTM, 'YYYYMMDD') AS REG_DTTM /*등록일시 */ , OIM.KT_ORG_ID /* KT조직ID */ , OIM.TYPE_DTL_CD1 /* 유형상세코드1 */ , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE CD_VAL = OIM.TYPE_DTL_CD1 AND USG_YN = 'Y') as TYPE_DTL_CD_NM1 , OIM.TYPE_DTL_CD2 /* 유형상세코드2 */ , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE CD_VAL = OIM.TYPE_DTL_CD2 AND USG_YN = 'Y' AND ETC1 IS NOT NULL) as TYPE_DTL_CD_NM2 , OIM.TYPE_DTL_CD3 /* 유형상세코드3 */ , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE CD_VAL = OIM.TYPE_DTL_CD3 AND USG_YN = 'Y' AND ETC1 IS NOT NULL) as TYPE_DTL_CD_NM3 FROM ORG_ORGN_INFO_MST OIM WHERE OIM.TYPE_DTL_CD = 'Y' AND OIM.TYPE_CD = '30'
AND OIM.ORGN_ID LIKE UPPER('%'||#{orgnId}||'%')
AND OIM.ORGN_NM LIKE '%'||#{orgnNm}||'%'
AND OIM.TYPE_CD = #{typeCd}
AND OIM.TYPE_CD = '30'
AND OIM.ORGN_LVL_CD = #{orgnLvlCd}
AND OIM.ORGN_LVL_CD = '20'
AND OIM.ORGN_STAT_CD = #{orgnStatCd}
ORDER BY ORGN_NM )

SELECT OIM.ORGN_ID /* 조직 ID */ , OIM.ORGN_NM /* 조직명 */ , OIM.TYPE_CD /* 유형코드 */ , FN_GET_CODENM('CMN0003', OIM.TYPE_CD) as TYPE_NM , OIM.ORGN_LVL_CD /* 조직레벨코드 */ , FN_GET_CODENM('CMN0006', OIM.ORGN_LVL_CD) as ORGN_LVL_NM , OIM.APPL_STRT_DT /* 적용시작일자 */ , OIM.APPL_CMPLT_DT /* 적용종료일자 */ , OIM.OPEN_CRDT_LOAN_YN /* 개통여신여부 */ , FN_GET_CODENM('ORG0012', OIM.OPEN_CRDT_LOAN_YN) as OPEN_CRDT_LOAN_NM , OIM.OPEN_CRDT_LOAN_STRT_DT /* 개통여신시작일자 */ , DECODE(OIM.TAXBILL_YN, 'Y','Y','N') AS TAXBILL_YN /* 세금계산서발행여부 */ , DECODE(OIM.CMSN_PRVD_YN, 'Y','Y','N') AS CMSN_PRVD_YN /* 수수료지급여부 */ , DECODE(OIM.HNDST_INVTR_YN, 'Y','Y','N') AS HNDST_INVTR_YN /* 단말재고여부 */ , OIM.BIZ_TYPE_CD /* 사업자구분 */ , FN_GET_CODENM('CMN0007', OIM.BIZ_TYPE_CD) as BIZ_TYPE_NM , OIM.BIZ_REG_NUM /* 사업자등록번호 */ , OIM.CORP_REG_NUM /* 법인등록번호 */ , OIM.BIZ_CAT /* 업종 */ , OIM.BIZ_CON /* 업태 */ , OIM.RPRSEN_NM /* 대표자명 */ , OIM.RPRSEN_RRNUM /* 대표자주민번호 */ , OIM.TELNUM /* 전화번호 */ , OIM.FAX /* 팩스번호 */ , OIM.EMAIL /* 이메일 */ , OIM.ZIPCD /* 우편번호 */ , OIM.ADDR1 /* 주소1 */ , OIM.ADDR2 /* 주소2 */ , OIM.RESPN_PRSN_ID /* 담당자ID */ , (SELECT USR_NM FROM CMN_USR_MST WHERE USR_ID = OIM.RESPN_PRSN_ID) as RESPN_PRSN_NM , (SELECT TEL_NUM FROM CMN_USR_MST WHERE USR_ID = OIM.RESPN_PRSN_ID) as RESPN_PRSN_NUM , (SELECT MBLPHN_NUM FROM CMN_USR_MST WHERE USR_ID = OIM.RESPN_PRSN_ID) as RESPN_PRSN_MBLPHN , (SELECT EMAIL FROM CMN_USR_MST WHERE USR_ID = OIM.RESPN_PRSN_ID) as RESPN_PRSN_EMAIL , OIM.HNDST_ORD_YN /* 단말주문여부 */ , OIM.ORGN_STAT_CD /* 조직상태코드 */ , FN_GET_CODENM('CMN0005', OIM.ORGN_STAT_CD) as ORGN_STAT_NM , OIM.TMNT_DT /* 해지일자 */ , OIM.TYPE_DTL_CD /* 유형상세코드 */ , FN_GET_CODENM('CMN0004', OIM.TYPE_DTL_CD) as TYPE_DTL_NM , OIM.HGHR_ORGN_CD /* 상위조직코드 */ , (SELECT ORGN_NM FROM ORG_ORGN_INFO_MST WHERE ORGN_ID = OIM.HGHR_ORGN_CD AND ROWNUM = 1) as HGHR_ORGN_NM /* 상위조직코드명 */ , OIM.ORGN_GRD /* 조직등급 */ , OIM.CLOSE_YN /* 정리점여부 */ , OIM.LOGIS_CNTER_YN /* 물류센터여부 */ , OIM.REG_ID /* 등록자ID */ , TO_CHAR(OIM.REG_DTTM, 'YYYYMMDD') AS REG_DTTM /*등록일시 */ , OIM.KT_ORG_ID /* KT조직ID */ , OIM.TYPE_DTL_CD1 /* 유형상세코드1 */ , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE CD_VAL = OIM.TYPE_DTL_CD1 AND USG_YN = 'Y') as TYPE_DTL_CD_NM1 , OIM.TYPE_DTL_CD2 /* 유형상세코드2 */ , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE CD_VAL = OIM.TYPE_DTL_CD2 AND USG_YN = 'Y' AND ETC1 IS NOT NULL) as TYPE_DTL_CD_NM2 , OIM.TYPE_DTL_CD3 /* 유형상세코드3 */ , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE CD_VAL = OIM.TYPE_DTL_CD3 AND USG_YN = 'Y' AND ETC1 IS NOT NULL) as TYPE_DTL_CD_NM3 FROM ORG_ORGN_INFO_MST OIM , ( /* 본사 사용자 */ SELECT OIM.ORGN_ID FROM ORG_ORGN_INFO_MST OIM WHERE OIM.TYPE_DTL_CD = 'Y' AND OIM.TYPE_CD != '30'
AND OIM.ORGN_ID LIKE UPPER('%'||#{orgnId}||'%')
AND OIM.ORGN_NM LIKE '%'||#{orgnNm}||'%'
AND OIM.TYPE_CD = #{typeCd}
AND OIM.TYPE_CD = '20'
AND OIM.ORGN_LVL_CD = #{orgnLvlCd}
AND OIM.ORGN_LVL_CD = '10'
AND OIM.ORGN_STAT_CD = #{orgnStatCd}
START WITH ORGN_ID = CASE WHEN EXISTS (SELECT ORGN_ID FROM ORG_ORGN_INFO_MST WHERE LOGIS_CNTER_YN = 'Y' and ORGN_ID = #{sessionUserOrgnId}) THEN '1' ELSE #{sessionUserOrgnId} END CONNECT BY PRIOR ORGN_ID = HGHR_ORGN_CD UNION /* 대리점 이하 사용자 */ SELECT OIM.ORGN_ID FROM ORG_ORGN_INFO_MST OIM WHERE OIM.TYPE_DTL_CD = 'Y' AND OIM.TYPE_CD = '30'
AND OIM.ORGN_ID LIKE UPPER('%'||#{orgnId}||'%')
AND OIM.ORGN_NM LIKE '%'||#{orgnNm}||'%'
AND OIM.TYPE_CD = #{typeCd}
AND OIM.TYPE_CD = '30'
AND OIM.ORGN_LVL_CD = #{orgnLvlCd}
AND OIM.ORGN_LVL_CD = '20'
AND OIM.ORGN_STAT_CD = #{orgnStatCd}
UNION /* 본사외 본사조직인 경우 */ SELECT OIM.ORGN_ID FROM ORG_ORGN_INFO_MST OIM WHERE OIM.TYPE_CD = '20' AND OIM.TYPE_DTL_CD = 'Y' AND EXISTS ( SELECT 1 FROM ORG_ORGN_INFO_MST WHERE TYPE_CD = '10' AND ORGN_ID = #{sessionUserOrgnId} )
AND OIM.ORGN_ID LIKE UPPER('%'||#{orgnId}||'%')
AND OIM.ORGN_NM LIKE '%'||#{orgnNm}||'%'
AND OIM.TYPE_CD = #{typeCd}
AND OIM.TYPE_CD = '20'
AND OIM.ORGN_LVL_CD = #{orgnLvlCd}
AND OIM.ORGN_LVL_CD = '10'
AND OIM.ORGN_STAT_CD = #{orgnStatCd}
) A WHERE OIM.ORGN_ID = A.ORGN_ID
AND OIM.ORGN_ID IN (SELECT CD_VAL FROM CMN_GRP_CD_MST WHERE GRP_ID = 'ORG0078' AND USG_YN = 'Y')

SELECT /* OrgMgmtMapper.treeListOrgMgmt */ OIM.ORGN_ID /* 조직 ID */ , OIM.ORGN_NM /* 조직명 */ , OIM.TYPE_CD /* 유형코드 */ ,(SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0003' AND CD_VAL = OIM.TYPE_CD) as TYPE_NM , OIM.ORGN_LVL_CD /* 조직레벨코드 */ ,(SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0006' AND CD_VAL = OIM.ORGN_LVL_CD) as ORGN_LVL_NM , OIM.APPL_STRT_DT /* 적용시작일자 */ , OIM.APPL_CMPLT_DT /* 적용종료일자 */ , OIM.OPEN_CRDT_LOAN_YN /* 개통여신여부 */ ,(SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'ORG0012' AND CD_VAL = OIM.OPEN_CRDT_LOAN_YN) as OPEN_CRDT_LOAN_NM , OIM.OPEN_CRDT_LOAN_STRT_DT /* 개통여신시작일자 */ , DECODE(OIM.TAXBILL_YN, 'Y','Y','N') AS TAXBILL_YN /* 세금계산서발행여부 */ , DECODE(OIM.CMSN_PRVD_YN, 'Y','Y','N') AS CMSN_PRVD_YN /* 수수료지급여부 */ , DECODE(OIM.HNDST_INVTR_YN, 'Y','Y','N') AS HNDST_INVTR_YN /* 단말재고여부 */ , OIM.BIZ_TYPE_CD /* 사업자구분 */ ,(SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0007' AND CD_VAL = OIM.BIZ_TYPE_CD) as BIZ_TYPE_NM , OIM.BIZ_REG_NUM /* 사업자등록번호 */ , OIM.CORP_REG_NUM /* 법인등록번호 */ , OIM.BIZ_CAT /* 업종 */ , OIM.BIZ_CON /* 업태 */ , OIM.RPRSEN_NM /* 대표자명 */ , OIM.RPRSEN_RRNUM /* 대표자주민번호 */ , OIM.TELNUM /* 전화번호 */ , OIM.FAX /* 팩스번호 */ , OIM.EMAIL /* 이메일 */ , OIM.ZIPCD /* 우편번호 */ , OIM.ADDR1 /* 주소1 */ , OIM.ADDR2 /* 주소2 */ , OIM.RESPN_PRSN_ID /* 담당자ID */ , OIM.RESPN_PRSN_ID AS RESPN_PRSN_ID_MSK /* 담당자ID */ ,(SELECT USR_NM FROM CMN_USR_MST WHERE USR_ID = OIM.RESPN_PRSN_ID) as RESPN_PRSN_NM ,(SELECT TEL_NUM FROM CMN_USR_MST WHERE USR_ID = OIM.RESPN_PRSN_ID) as RESPN_PRSN_NUM ,(SELECT MBLPHN_NUM FROM CMN_USR_MST WHERE USR_ID = OIM.RESPN_PRSN_ID) as RESPN_PRSN_MBLPHN ,(SELECT EMAIL FROM CMN_USR_MST WHERE USR_ID = OIM.RESPN_PRSN_ID) as RESPN_PRSN_EMAIL , OIM.HNDST_ORD_YN /* 단말주문여부 */ , OIM.ORGN_STAT_CD /* 조직상태코드 */ ,(SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0005' AND CD_VAL = OIM.ORGN_STAT_CD) as ORGN_STAT_NM , OIM.TMNT_DT /* 해지일자 */ , OIM.TYPE_DTL_CD /* 유형상세코드 */ ,(SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0004' AND CD_VAL = OIM.TYPE_DTL_CD) as TYPE_DTL_NM , OIM.HGHR_ORGN_CD /* 상위조직코드 */ ,(SELECT ORGN_NM FROM ORG_ORGN_INFO_MST WHERE ORGN_ID = OIM.HGHR_ORGN_CD AND ROWNUM = 1) as HGHR_ORGN_NM /* 상위조직코드명 */ , OIM.ORGN_GRD /* 조직등급 */ , FN_GET_CODENM('ORG0055', OIM.ORGN_GRD) AS ORGN_GRD_NM /* 대리점권역명 */ , OIM.CLOSE_YN /* 정리점여부 */ , OIM.LOGIS_CNTER_YN /* 물류센터여부 */ , OIM.REG_ID /* 등록자ID */ , TO_CHAR(OIM.REG_DTTM, 'YYYYMMDD') AS REG_DTTM /*등록일시 */ , OIM.KT_ORG_ID /* KT조직ID */ , OIM.TYPE_DTL_CD1 /* 유형상세코드1 */ , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE CD_VAL = OIM.TYPE_DTL_CD1 AND USG_YN = 'Y') as TYPE_DTL_CD_NM1 , OIM.TYPE_DTL_CD2 /* 유형상세코드2 */ , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE CD_VAL = OIM.TYPE_DTL_CD2 AND USG_YN = 'Y' AND ETC1 IS NOT NULL) as TYPE_DTL_CD_NM2 , OIM.TYPE_DTL_CD3 /* 유형상세코드3 */ , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE CD_VAL = OIM.TYPE_DTL_CD3 AND USG_YN = 'Y' AND ETC1 IS NOT NULL) as TYPE_DTL_CD_NM3 , CASE WHEN (SELECT COUNT(*) FROM ORG_ORGN_INFO_MST WHERE HGHR_ORGN_CD = OIM.ORGN_ID AND TYPE_DTL_CD = 'Y' AND TYPE_CD != '40' ) > 0 THEN 'true' ELSE 'false' END XMLKIDS_BO , DECODE(OIM.MCLUB_YN, 'Y', 'Y', 'N') AS MCLUB_YN /*M클럽점여부*/ FROM ORG_ORGN_INFO_MST OIM WHERE OIM.TYPE_DTL_CD = 'Y' AND OIM.TYPE_CD != '40'
AND OIM.ORGN_ID LIKE UPPER('%'||#{orgnId}||'%')
AND OIM.ORGN_NM LIKE '%'||#{orgnNm}||'%'
AND OIM.TYPE_CD = #{typeCd}
AND OIM.TYPE_CD = 20
AND OIM.ORGN_LVL_CD = #{orgnLvlCd}
AND OIM.ORGN_LVL_CD = 10
AND OIM.ORGN_STAT_CD = #{orgnStatCd}
AND OIM.HGHR_ORGN_CD = #{orgnId}
AND OIM.ORGN_LVL_CD = 1
ORDER BY OIM.ORGN_NM

SELECT /* OrgMgmtMapper.listCntOrgMgmt */
      COUNT(*)
  FROM ORG_ORGN_INFO_MST A
 WHERE A.TYPE_DTL_CD = 'Y'

        AND A.ORGN_ID LIKE UPPER(#{orgnId}) 


        AND A.ORGN_NM LIKE #{orgnNm}


        AND A.TYPE_CD = #{typeCd}


        AND A.TYPE_DTL_CD = #{typeDtlCd}


        AND A.ORGN_GRD = #{orgnGrd}


        AND A.BIZ_REG_NUM = #{bizRegNum}

