/* orgMgmtMapper.listOrgChgHst */
select TO_CHAR(ORG_CHG_DATE, 'YYYYMMDD') as ORG_CHG_DATE , ORGN_ID , ORGN_NM , TYPE_CD , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0003' AND CD_VAL = OCH.TYPE_CD) as TYPE_NM , KT_ORG_ID , HGHR_ORGN_CD , (SELECT ORGN_NM FROM ORG_ORGN_INFO_MST WHERE ORGN_ID = OCH.HGHR_ORGN_CD AND ROWNUM = 1) HGHR_ORGN_NM, ORGN_STAT_CD , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0005' AND CD_VAL = OCH.ORGN_STAT_CD) as ORGN_STAT_NM , USE_YN , APPL_CMPLT_DT , ARNO_ADR_ZIPCD||' '||ARNO_ADR_BAS_SBST||' '||ARNO_ADR_DTL_SBST ||''||ADR_RFRN_SBST as ARNO_ADR, ROADN_ADR_ZIPCD||' '||ROADN_ADR_BAS_SBST||' '||ROADN_ADR_DTL_SBST||''||ADR_RFRN_SBST as ROADN_ADR, ADM_USER_ID , MVNO_ORG_ID from ORG_ORGN_CHG_HST OCH where 1=1
and TO_CHAR(ORG_CHG_DATE , 'yyyymmdd') BETWEEN #{sysRdateS} AND #{sysRdateE}
and ORGN_ID = #{searchVal}
and ORGN_NM like '%'||#{searchVal}||'%'
and TYPE_CD = #{typeCd}
and ORGN_STAT_CD = #{orgnStatCd}
order by ORG_CHG_DATE DESC, ORGN_ID

/* orgMgmtMapper.listOrgChgHstExcel */ select TO_CHAR(ORG_CHG_DATE, 'YYYY-MM-DD') as ORG_CHG_DATE , ORGN_ID , ORGN_NM , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0003' AND CD_VAL = OCH.TYPE_CD) as TYPE_NM , KT_ORG_ID , (SELECT ORGN_NM FROM ORG_ORGN_INFO_MST WHERE ORGN_ID = OCH.HGHR_ORGN_CD AND ROWNUM = 1) HGHR_ORGN_NM, (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0005' AND CD_VAL = OCH.ORGN_STAT_CD) as ORGN_STAT_NM , USE_YN , SUBSTR(APPL_CMPLT_DT, 1, 4)||'-'||SUBSTR(APPL_CMPLT_DT, 5, 2)||'-'||SUBSTR(APPL_CMPLT_DT, 7, 2) as APPL_CMPLT_DT, ARNO_ADR_ZIPCD, ARNO_ADR_BAS_SBST, ARNO_ADR_DTL_SBST, ARNO_ADR_BROAD_NM, ARNO_ADR_MDAR_NM, ARNO_ADR_BMAS_NM, ARNO_ADR_MYUN_DNGL_NM, ARNO_ADR_BJ_NM, ARNO_ADR_DONG_CD, ROADN_ADR_ZIPCD, ROADN_ADR_BAS_SBST, ROADN_ADR_DTL_SBST, ROADN_ADR_BROAD_NM, ROADN_ADR_MDAR_NM, ROADN_ADR_BMAS_NM, ROADN_ADR_ROAD_NM, ROADN_ADR_BLDG_NO, ADR_RFRN_SBST, ADM_USER_ID , MVNO_ORG_ID from ORG_ORGN_CHG_HST OCH where 1=1
and TO_CHAR(ORG_CHG_DATE , 'yyyymmdd') BETWEEN #{sysRdateS} AND #{sysRdateE}
and ORGN_ID = #{searchVal}
and ORGN_NM like '%'||#{searchVal}||'%'
and TYPE_CD = #{typeCd}
and ORGN_STAT_CD = #{orgnStatCd}
order by ORG_CHG_DATE DESC, ORGN_ID
